// src/views/user/MyProfile/composables/useModules.js
import { ref } from 'vue'
import { showToast } from '@/components/ToastMessage'
import { user } from '@/api/user'
import { useProfileData } from './useProfileData'

// 定义默认布局配置和模块名称映射
const DEFAULT_LAYOUT = {
  basic_info: { 
    order: 1, 
    visible: true,
    name: '基本信息'
  },
  job_intention: { 
    order: 2, 
    visible: true,
    name: '求职意向'
  },
  work_experience: { 
    order: 3, 
    visible: true,
    name: '工作经历'
  },
  education: { 
    order: 4, 
    visible: true,
    name: '教育经历'
  },
  project: { 
    order: 5, 
    visible: false,
    name: '项目经历'
  },
  skill: { 
    order: 6, 
    visible: false,
    name: '专业技能'
  },
  certificate: { 
    order: 7, 
    visible: false,
    name: '证书奖项'
  },
  language: { 
    order: 8, 
    visible: false,
    name: '语言能力'
  },
  portfolio: { 
    order: 9, 
    visible: false,
    name: '作品展示'
  },
  social_link: { 
    order: 10, 
    visible: false,
    name: '社交主页'
  }
}

// 获取模块显示名称
const getModuleName = (type) => {
  return DEFAULT_LAYOUT[type]?.name || type
}

export function useModules() {
  const { fetchModuleData } = useProfileData()
  const loading = ref(false)
  const activeModules = ref([])
  const inactiveModules = ref([])

  // 获取布局和模块数据
  const fetchModulesData = async () => {
    try {
      loading.value = true
      console.log('开始获取模块数据')

      const response = await user.getProfileLayout()
      console.log('布局响应:', response.data)

      if (response.data?.code === 200) {
        // 获取布局数据，如果没有布局数据则使用默认布局
        const serverLayout = response.data.data?.layout || {}
        console.log('服务器布局数据:', serverLayout)

        // 合并默认布局和服务器布局
        const mergedLayout = Object.entries(DEFAULT_LAYOUT).reduce((acc, [key, defaultConfig]) => {
          const serverConfig = serverLayout[key] || {}
          acc[key] = {
            type: key,
            name: defaultConfig.name,
            order: serverConfig.order || defaultConfig.order,
            visible: serverConfig.visible ?? defaultConfig.visible
          }
          return acc
        }, {})
        console.log('合并后的布局:', mergedLayout)

        // 分离激活和未激活的模块
        const activeModuleConfigs = []
        const inactiveModuleConfigs = []

        Object.values(mergedLayout).forEach(config => {
          if (config.type !== 'basic_info') {
            if (config.visible) {
              activeModuleConfigs.push(config)
            } else {
              inactiveModuleConfigs.push(config)
            }
          }
        })

        // 获取激活模块的数据
        const activePromises = activeModuleConfigs.map(async (config) => {
          const moduleData = await fetchModuleData(config.type)
          return {
            ...config,
            data: moduleData
          }
        })

        // 等待所有数据加载完成
        const activeResults = await Promise.all(activePromises)

        // 更新状态
        activeModules.value = activeResults.sort((a, b) => a.order - b.order)
        inactiveModules.value = inactiveModuleConfigs.sort((a, b) => a.order - b.order)

        console.log('激活的模块:', activeModules.value)
        console.log('未激活的模块:', inactiveModules.value)
      }
    } catch (error) {
      console.error('获取模块数据失败:', error)
      showToast('获取模块数据失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  // 添加模块
  const addModule = async (moduleType) => {
    try {
      loading.value = true
      console.log('开始添加模块:', moduleType)

      // 1. 准备新的布局数据
      const layout = {}

      // 添加所有已激活的模块
      activeModules.value.forEach(module => {
        layout[module.type] = {
          visible: true,
          order: module.order
        }
      })

      // 添加要激活的模块
      layout[moduleType] = {
        visible: true,
        order: activeModules.value.length + 1
      }

      // 添加所有未激活的模块
      inactiveModules.value.forEach(module => {
        if (module.type !== moduleType) {
          layout[module.type] = {
            visible: false,
            order: module.order
          }
        }
      })

      console.log('发送的布局数据:', { data: { layout } })

      const response = await user.updateProfileLayout({ data: { layout } })
      console.log('服务器响应:', response.data)

      if (response.data?.code === 200) {
        // 立即更新本地状态
        const moduleToAdd = inactiveModules.value.find(m => m.type === moduleType)
        if (moduleToAdd) {
          moduleToAdd.visible = true
          const moduleIndex = inactiveModules.value.findIndex(m => m.type === moduleType)
          inactiveModules.value.splice(moduleIndex, 1)
          activeModules.value.push(moduleToAdd)
        }

        // 重新获取完整数据
        await fetchModulesData()
        showToast('模块已添加', 'success')
      } else {
        throw new Error(response.data?.message || '添加失败')
      }
    } catch (error) {
      console.error('添加模块失败:', error)
      showToast(error.message || '添加模块失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  // 移除模块
  const removeModule = async (moduleType) => {
    try {
      loading.value = true
      console.log('开始移除模块:', moduleType)

      // 1. 准备新的布局数据
      const layout = {}

      // 处理所有模块
      activeModules.value.forEach(module => {
        layout[module.type] = {
          visible: module.type !== moduleType,
          order: module.order
        }
      })

      inactiveModules.value.forEach(module => {
        layout[module.type] = {
          visible: false,
          order: module.order
        }
      })

      console.log('发送的布局数据:', { data: { layout } })

      const response = await user.updateProfileLayout({ data: { layout } })
      console.log('服务器响应:', response.data)

      if (response.data?.code === 200) {
        // 立即更新本地状态
        const moduleToRemove = activeModules.value.find(m => m.type === moduleType)
        if (moduleToRemove) {
          moduleToRemove.visible = false
          const moduleIndex = activeModules.value.findIndex(m => m.type === moduleType)
          activeModules.value.splice(moduleIndex, 1)
          inactiveModules.value.push(moduleToRemove)
        }

        // 重新获取完整数据
        await fetchModulesData()
        showToast('模块已移除', 'success')
      } else {
        throw new Error(response.data?.message || '移除失败')
      }
    } catch (error) {
      console.error('移除模块失败:', error)
      showToast(error.message || '移除模块失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    activeModules,
    inactiveModules,
    fetchModulesData,
    addModule,
    removeModule
  }
}
